public static boolean checkBLNum(String30 blNum, DataAreaId dataAreaId, ModuleSalesPurch salesPurchase, String30 purchSalesId)
{
    boolean ret = true;

    if(ETGACFParameters::find().EnableBLNumberUniqueValidation == NoYes::Yes)
    {
        if(blNum)
        {
            if(salesPurchase == ModuleSalesPurch::Purch)
            {
                VendPackingSlipJour vendPackingSlipJourBLNum;
                PurchLine purchLineBLNum;
                select firstonly vendPackingSlipJourBLNum
                where vendPackingSlipJourBLNum.BOLNo == blNum
                && vendPackingSlipJourBLNum.DataAreaId == dataAreaId;

                if(vendPackingSlipJourBLNum)
                {
                    select firstonly RecId from purchLineBLNum
                        where purchLineBLNum.PurchId == purchSalesId
                        && purchLineBLNum.DataAreaId == dataAreaId
                        && purchLineBLNum.PurchQty < 0;

                    if(!purchLineBLNum.RecId)
                    {
                        ret = checkFailed(strFmt("@ETG_New:BLNumberUniqueValidationPurch", blNum, vendPackingSlipJourBLNum.PurchId));
                    }
                }
            }

            if(salesPurchase == ModuleSalesPurch::Sales)
            {
                CustPackingSlipJour custPackingSlipJourBLNum;
                SalesLine salesLineBLNum;
                select firstonly custPackingSlipJourBLNum
                where custPackingSlipJourBLNum.BOLNo == blNum
                && custPackingSlipJourBLNum.DataAreaId == dataAreaId;

                if(custPackingSlipJourBLNum)
                {
                    select firstonly RecId from salesLineBLNum
                        where salesLineBLNum.SalesId == purchSalesId
                        && salesLineBLNum.DataAreaId == dataAreaId
                        && salesLineBLNum.SalesQty < 0;

                    if(!salesLineBLNum.RecId)
                    {
                        ret = checkFailed(strFmt("@ETG_New:BLNumberUniqueValidationSales", blNum, custPackingSlipJourBLNum.SalesId));
                    }
                }
            }
        }
    }

    return ret;
}
